ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  id: vars.taskId,
  contextId: vars.contextId,
  kind: "task",
  status: {
    state: "completed",
    message: {
      role: "agent",
      kind: "message",
      messageId: (now() as String) ++ "-" ++ vars.taskId,
      parts: [
        { kind: "text", text: vars.replyText default "" }
      ]
    },
    timestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss'Z'" }
  }
}

%dw 2.0
output application/java
---
[
  { "type": "function", "function": {
      name: "get_alternative_parts",
      description: "代替部品候補を IDMC KG から互換スコア降順で取得",
      parameters: {
        "type": "object",
        properties: { partNumber: { "type": "string" } },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "create_purchase_order_draft",
      description: "代替発注書ドラフトを生成する",
      parameters: {
        "type": "object",
        properties: {
          partNumber:       { "type": "string" },
          quantity:         { "type": "integer" },
          supplierGoldenId: { "type": "string" },
          incidentId:       { "type": "string" },
          unitPrice:        { "type": "number" }
        },
        required: ["partNumber", "quantity", "supplierGoldenId"]
      }
  }},
  { "type": "function", "function": {
      name: "notify_supplier",
      description: "サプライヤーへ通知を送る (ORDER / CANCEL / INFO)",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          "type":           { "type": "string", "enum": ["ORDER", "CANCEL", "INFO"] },
          message:          { "type": "string" },
          incidentId:       { "type": "string" }
        },
        required: ["supplierGoldenId", "type", "message"]
      }
  }}
]

%dw 2.0
output application/java
fun safeReadJson(s: String) =
  if (s == null or trim(s) == "") {}
  else read(s, "application/json")
---
if (payload == null) {}
else if (payload is Binary) safeReadJson(payload as String { encoding: "UTF-8" })
else if (payload is String) safeReadJson(payload as String)
else payload
